```

```javascript
// Callback function
function greet(name, callback) {
    console.log('Hello, ' + name + '!');
    callback();
}

function sayGoodbye() {
    console.log('Goodbye!');
}

// Usage
greet('Alice', sayGoodbye);
// Outputs:
// Hello, Alice!
// Goodbye!
```
